using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    // The default resolver that uses reflection; knows about any type at runtime.
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// ── 1. Strongly-typed metadata retrieval ──────────────────────────
// GetTypeInfo<T>() returns JsonTypeInfo<T> directly — no cast needed.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata  : {personInfo.Type.Name}  (kind: {personInfo.Kind})");

string json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"Serialized with it  : {json}");

Person deserialized = JsonSerializer.Deserialize(json, personInfo)!;
Console.WriteLine($"Deserialized back   : {deserialized}");

// ── 2. Probe without throwing ─────────────────────────────────────
// TryGetTypeInfo returns false instead of throwing when metadata
// isn't available (e.g. the resolver can't handle the type).
var restrictedOptions = new JsonSerializerOptions
{
    // An empty resolver chain — knows about nothing.
    TypeInfoResolverChain = { }
};

if (restrictedOptions.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info))
{
    Console.WriteLine($"Found metadata      : {info!.Type.Name}");
}
else
{
    Console.WriteLine("No metadata for Person (resolver can't handle it) — no exception!");
}

// Contrast: the default resolver succeeds.
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info2))
{
    Console.WriteLine($"Default resolver OK : {info2!.Type.Name}");
}

record Person(string Name, int Age);
EOF

